132	  case XY_FORCED_MODE:
133	    ret->common.append = (void (*)(view *, ...))append_forced;
134	    ret->common.set = NULL;
135	    ret->length = 0;
136	    ret->max_length = length;
137	    break;
138	  }
139	
140	  ret->refresh_rate = refresh_rate;
141	  ret->g = g;
142	  ret->w = w;
143	  ret->plot = xy_plot_new_plot(g, w, color);
144	
145	  ret->x = calloc(length, sizeof(float)); if (ret->x == NULL) abort();
146	  ret->y = calloc(length, sizeof(float)); if (ret->y == NULL) abort();
147	
148	  if (pthread_mutex_init(&ret->lock, NULL)) abort();
